var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"언니!","JPN":"姉さん！","ENG":"Sis!","TWN":"姊姊！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"아, 솔로베.","JPN":"あ、ソロベー。","ENG":"Ah, Solovey.","TWN":"啊，蘇羅薇。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"미안. 그 침식체 녀석, 거의 잡을 뻔했는데. 방심해서 놓쳤어.","JPN":"ごめんね。あの侵食体、捕まえられそうだったのに。油断して逃がしちゃった。","ENG":"Sorry. I nearly caught that C.O., but I let my guard down and missed her.","TWN":"對不起，差一點就能抓住那隻侵蝕體了……但我太大意了，讓她跑了。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"언니는요? 안 다쳤어요?","JPN":"姉さんは？　怪我はないですか？","ENG":"What about you, Sis? Are you not hurt?","TWN":"姊姊呢？沒受傷吧？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"녀석한테 기습당했는데, 간신히 피했어.","JPN":"想定外の奇襲を受けたけど、何とかよけたわ。","ENG":"I was ambushed, but I managed to dodge her.","TWN":"被那傢伙偷襲了，但好歹躲過去了。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"다른 두 사람까지 지키진 못했지만.","JPN":"他の2人までは守れなかったけど。","ENG":"I couldn't protect the other two, though.","TWN":"只是……沒能保護住另外兩個人。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"다른 두 사람이라면…?","JPN":"他の2人って……？","ENG":"The other two...?","TWN":"另外兩個人是……？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"애니 양과… 이유미 경정님이 침식체의 공격에 다쳤어요.","JPN":"エニーさんと……カスカベ警視が侵食体の攻撃で怪我をしました。","ENG":"Annie... and Major Lee were injured by the C.O.'s attack.","TWN":"安妮和……李悠美長官因侵蝕體襲擊而受傷了。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"올리비에 박사님 말씀으론, 두 사람 모두 다른 피해자들처럼 CRF소실증을 겪고 있대요.","JPN":"オリヴィエ博士の話によると、2人とも他の被害者のようにCRF消失症になっているそうです。","ENG":"According to Dr. Olivie, both of them are experiencing CRF loss, just like the other victims.","TWN":"奧利維亞博士說，兩人都跟其他受害者一樣，患上了CRF喪失症。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"CRF 소실증? 그게 뭐죠?","JPN":"CRF消失症？　何ですか、それ？","ENG":"CRF loss? What's that?","TWN":"CRF喪失症？那是什麼？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"CRF는 카운터가 가진 힘이야.","JPN":"CRFはカウンターが持つ力のこと。","ENG":"CRF is the power that a Counter possesses.","TWN":"CRF是制裁者的力量核心。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그리고 환자의 몸을 잠식한 침식 바이러스가 그 CRF의 활성을 막고 있다는 거지.","JPN":"そして患者の体に浸透した侵食ウイルスがそのCRFの活性化を邪魔しているみたいなの。","ENG":"And the Corruption virus that has infested the patient's body is blocking the activation of that CRF.","TWN":"寄生在患者體內的侵蝕病毒正在阻止CRF的活性。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"전문가 분들이 치료 방법을 찾고 있지만, 현재로선 회복할 방법이 없어.","JPN":"専門家が今治療方法を探しているけど、今のところは回復方法が見つかってないわ。","ENG":"Experts are working on finding a treatment, but for now, there's no way to recover.","TWN":"專家們正在尋找治療方法，但目前沒有能夠恢復的辦法。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"힘을 못 쓰게 됐을 뿐이라면… 건강은 괜찮은 거겠죠?","JPN":"力が使えなくなっただけなら……命には問題ないんですよね？","ENG":"If they just can't use their power... that means their health should be fine, right?","TWN":"如果只是無法使用能力……身體健康應該沒問題吧？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐, 카운터 능력을 쓰지 못할 뿐이니까 괜찮을 거라고 생각하지만…","JPN":"まぁ、カウンター能力を使えなくなっただけだから問題ないと思いますが……","ENG":"Well, I think they should be fine since they just can't use their Counter ability...","TWN":"嗯，理論上只是無法使用制裁者的能力，應該不會有生命危險……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그 점도 안심할 순 없어요.","JPN":"その点も安心できません。","ENG":"But we can't be sure of that.","TWN":"但也不能掉以輕心。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"차라리 카운터에서 일반인이 된 거라면 지장이 없겠지만, 카운터는 일반인과 달리 CRF의 의존도가 높거든요.","JPN":"カウンターから一般人になっただけなら問題ないでしょうが、カウンターは普通の人とは違ってCRFに対する依存度が高いんです。","ENG":"If they've turned from Counters into non-Counters, it wouldn't be an issue. But Counters have a higher dependency on CRF compared to non-Counters.","TWN":"如果只是變回普通人，那倒還好，但制裁者不同於普通人，對CRF的依賴度更高。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"하지만 바이러스가 전신에 스며들어 수술로는 제거가 불가능한 데다, 이 바이러스는 점점 강해지고 있어요.","JPN":"しかしウイルスが全身に広がっているため手術では除去できませんし、ウイルス自体もどんどん強くなっています。","ENG":"The virus has spread throughout their body, and it's impossible to remove it through surgery. On top of that, this virus is getting stronger.","TWN":"更何況病毒已經滲透全身，用手術無法清除，而且還在不斷增強。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그 말씀은… 목숨이 위험하단 건가요?","JPN":"それは……命が危ないということですか？","ENG":"Does that mean... their lives are in danger?","TWN":"你的意思是……他們的生命也會受到威脅？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"지금 같은 기세라면, 길어야 일주일이 한계입니다.","JPN":"このまま行けば、長くもってもあと1週間で限界が来ます。","ENG":"At the current rate, it's likely they only have a week at most.","TWN":"照現在這種情況，最多只能撐一周。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"CRF를 쓰지 않아도 계속 빼앗기다가 결국엔 완전히 고갈되고 말겠죠.","JPN":"CRFを使わなくても、奪われ続けていずれは完全になくなるでしょう。","ENG":"Even without using CRF, they'll keep losing it until it's completely depleted.","TWN":"即便不使用CRF，他們的能量也會持續遭到剝奪，直到完全枯竭。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"박사님. 뭔가 해결책은 없는 건가요?","JPN":"博士。何か解決策はないんですか？","ENG":"Doctor, is there no solution?","TWN":"博士，有沒有解決辦法？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"확실한 치료법을 말하는 거라면, 아직 없어요.","JPN":"確実な治療方法のことでしたら、まだありません。","ENG":"If you're asking about a definite cure, there's none yet.","TWN":"如果問的是明確的治療方法，目前沒有。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"하지만 어쩌면… 치료가 아닌 다른 해결책은 있을 지도 모르지만요.","JPN":"でも、もしかしたら……治療ではない、他の解決策はあるかもしれません。","ENG":"But perhaps... there might be another solution, one that isn't a cure.","TWN":"但或許……可以嘗試其他方法。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그게 뭐죠? 말씀해주세요!","JPN":"それは何ですか？　教えてください！","ENG":"What is it? Please, tell me!","TWN":"是什麼？請告訴我們！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};